237	            // ── 2. Initialize if empty ───────────────────────────────────────────────
238	            const initialization = initializeFieldsOrderIfEmpty(
239	                currentFieldsOrder,
240	                fieldsStore.customFieldsData,
241	                fieldsRegistry,
242	                dbCustomFieldChangeTime
