249	                }
250	                return initialization.fieldsOrder;
251	            }
252	    
253	            // ── 3. Clean up flag-gated fields and duplicates ─────────────────────────
254	            const cleaned = cleanupFieldsOrder(
255	                currentFieldsOrder,
256	                fieldsRegistry,
257	                organizationStore.userOrganizationDetails.is_lgbtq,
