import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useUsersStore } from '../../store/users/usersStore';
import { Age } from '../../Table/Users/Age';
import { Gender } from '../../Table/Users/Gender/Gender';
import { Img } from '../../Table/common/Img';
import { ConversationLength } from '../../Table/Users/ConversationLength';
import { Objectives } from '../../Table/Users/Objectives';
import { Pin } from '../../Table/common/Pin';
import { Completion } from '../../Table/common/Completion/Completion';
import { RelationshipStatus } from '../../Table/Users/RelationshipStatus';
import { Status } from '../../Table/Users/Status';
import { useSystemStore } from '../../store/system/systemStore';
import { useConversationStore } from '../../store/conversation/conversationStore';
import UserSearchQuery from '../../components/userFilters/UserSearchQuery/UserSearchQuery';
import UserSearchFilters from '../../components/userFilters/UserSearchFilters/UserSearchFilters';
import { useProfileStore } from '../../store/profile/profileStore';
import { getFacialPhotoSource, getTimeDifferenceString, isRTL, getModuleLicense } from '../../helpers';
import {
    MENU_ACTION_COLUMN_NAME, AVATAR_IMG_WIDTH_HEIGHT, EMPTY_USER_FILTERS, MODULE, MODULE_ICONS, NOTIFICATION_SEVERITIES, USER_ENTITY_FIELDS, USER_PHOTO_TRANSFORM, } from '../../constants';
import { Height } from '../../Table/Users/Height';
import { YesOrNo } from '../../Table/common/YesOrNo';
import { CUSTOM_FIELD_MIN_WIDTH, CUSTOM_FIELD_MIN_WIDTH_SMALL, CustomField } from '../../Table/Users/CustomField/CustomField';
import { Date } from '../../Table/common/Date';
import './Users.scss';
import i18n from '../../i18n';
import { isNameAvailable, useOrganizationStore } from '../../store/organization/organizationStore';
import { useFieldsStore } from '../../store/fields/fieldsStore';
import { COLUMN_SELECTION_CATEGORIES } from '../../Table/Users/helpers';
import UserInfoCard from '../../components/userInfoBigCard/UserInfoCard/UserInfoCard';
import { convertModulesToInt } from '../../store/system/helpers';
import { usePackageStore } from '../../store/package/packageStore';
import { String } from '../../Table/common/String';
import { Name } from '../../Table/Users/Name';
import { Button, IconButton, Tooltip } from '@mui/material';
import DeselectIcon from '@mui/icons-material/Deselect';
import { EditModeButton, getDateFromTimestamp, isEmptyValue, buildDataString } from "@ob-love/ui";
import DefaultFiltersButton from '../../components/userFilters/DefaultFiltersButton/DefaultFiltersButton';
import { showCreateNewUserDialog, showDeleteUserDialog, showSetUserInactiveDialog, showPromoteToUserDialog, showFormSelectionDialog } from '../../store/window/helpers';
import { useNotificationSystemStore } from '../../store/notificationSystem/notificationSystemStore';
import { DateTimeStamp } from '../../Table/common/DateTimeStamp';
import { useSelectedUsersStore } from '../../store/users/selectedUsersStore';
import { Select } from '../../Table/Users/Select/Select';
import { MenuAction } from '../../Table/common/MenuAction/MenuAction';
import moment from 'moment';
import { useUserCommentStore } from '../../store/userComment/userCommentStore';
import { useFormStore } from '../../store/form/formStore';
import { useWindowStore } from '../../store/window/windowStore';
import CreateUserIcon from '../../assets/icons/CreateUserIcon';
import PageLayoutTableDrawerFilter from '../../components/Layout/PageLayoutTableDrawerFilter';
import { useHelpStore } from '../../store/help/helpStore';
import Help from '../../components/Help/Help';
import FilterQueryActions from '../../components/QueryFilter/FilterQueryActions/FilterQueryActions';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faThumbtackSlash } from '@fortawesome/free-solid-svg-icons';
import { Type } from '../../Table/Users/Type';
import { FindMatches } from '../../Table/Users/FindMatches';
import { mergeFieldMappings, handleCustomFieldChanges, initializeFieldsOrderIfEmpty, cleanupFieldsOrder } from '../../components/User/fieldOrderHelpers';
import { createFieldMenuItems, buildUserRowMenuItems } from '../../MenuItem/Users/menuItems';
import { buildFieldRegistry } from '../../components/User/fieldRegistry';
import { useUiSettingsStore } from '../../store/uiSettings/uiSettingsStore';
import { useAdminUserStore } from '../../store/adminUser/adminUserStore';
import { RelationshipTimeline } from '../../Table/Users/RelationshipTimeline';
import { Orientation } from '../../Table/Users/Orientation';
import { useGodStore } from '../../store/god/godStore';
import { buildCustomFieldCategoryMap, getFieldUpdateSuccessMessage, getIsUserField } from '../../components/CustomField/helpers';
import { useLayout } from '../../components/PageLayout/LayoutContext/LayoutContext';
import { useLocalStorageStore } from '../../store/localStorage/localStorageStore';
import { useWorkflowStore } from '../../store/workflow/workflowStore';
import { GenderIdentity } from '../../Table/Users/GenderIdentity';
import { buildFindMatchesFilter, is_show_on_manual_user_create } from '../../components/User/helpers';
import { applySearchableOverrides } from '../../store/uiSettings/helpers';
import { useNavigate } from 'react-router-dom';

const Users = (props) => {
    const gridRef = useRef();
    const createUserContentRef = useRef();
    const navigate = useNavigate();

    const usersState = useUsersStore((state) => state);
    const systemStore = useSystemStore((state) => state);
    const profileStore = useProfileStore((state) => state);
    const conversationStore = useConversationStore((state) => state);
    const organizationStore = useOrganizationStore((state) => state);
    const fieldsStore = useFieldsStore((state) => state);
    const packageStore = usePackageStore((state) => state);
    const selectedUserStore = useSelectedUsersStore((state) => state);
    const userCommentStore = useUserCommentStore((state) => state);
    const formStore = useFormStore((state) => state);
    const uiSettingsStore = useUiSettingsStore((state) => state);
    const helpStore = useHelpStore((state) => state);
    const adminUserStore = useAdminUserStore((state) => state);
    const godStore = useGodStore((state) => state);
    const workflowStore = useWorkflowStore((state) => state);

    const [columns, setColumns] = useState([]);
    const [drawerOpen, setDrawerOpen] = useState(false);
    const [isPartnerSelected, setIsPartnerSelected] = useState(false);
    const [showProfile, setShowProfile] = useState(false);
    const [showConversationDiff, setShowConversationDiff] = useState(false);
    const [showConversationStats, setShowConversationStats] = useState(false);
    const [isDrawerEditMode, setIsDrawerEditMode] = useState(false);
    const [isFilterEditMode, setIsFilterEditMode] = useState(false);

    const { setLayoutProps } = useLayout();

    const LICENSE = getModuleLicense(systemStore.constants.module_type.USER);
    const IS_OWNER = adminUserStore.userInfo?.is_owner;
    const IS_EDIT_LICENSE = LICENSE <= systemStore.constants.license_type.UPDATE;

    const onFilterTabsReorder = (newTabs) => {
        uiSettingsStore.setSearchFilterTabsOrder(MODULE.USER, newTabs.map(tab => tab.value));
    };

    const savedDefaultFilters = uiSettingsStore.uiSettings[MODULE.USER]?.searchFilter?.default ?? null;

    const cloneFilters = (filters) => JSON.parse(JSON.stringify(filters || {}));

    const filterTopRightActions = useMemo(() => {
        const actions = [
            <EditModeButton
                key='search_filter_edit_mode'
                isActive={isFilterEditMode}
                onClick={() => setIsFilterEditMode(!isFilterEditMode)}
            />
        ];
        if (IS_OWNER) {
            actions.push(
                <DefaultFiltersButton
                    key='default_filters_button'
                    currentFilters={usersState.filtersSelected}
                    defaultFilters={savedDefaultFilters}
                    packages={packageStore.packages}
                    measurement_unit={organizationStore.userOrganizationDetails.measurement_unit}
                    entityType='users'
                    onSetDefault={() => {
                        const hasKeys = usersState.filtersSelected && Object.keys(usersState.filtersSelected).length > 0;
                        const snapshot = hasKeys ? cloneFilters(usersState.filtersSelected) : cloneFilters(EMPTY_USER_FILTERS);
                        uiSettingsStore.setDefaultSearchFilters(MODULE.USER, snapshot);
                    }}
                    onApplyDefault={() => {
                        usersState.onFiltersSelected(cloneFilters(savedDefaultFilters || EMPTY_USER_FILTERS));
                        resetGrid();
                    }}
                    onClearDefault={() => {
                        uiSettingsStore.resetDefaultSearchFilters(MODULE.USER);
                    }}
                />
            );
        }
        return actions;
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        isFilterEditMode,
        IS_OWNER,
        usersState.filtersSelected,
        savedDefaultFilters,
        packageStore.packages,
        organizationStore.userOrganizationDetails.measurement_unit,
    ]);
    // Create onUpdateUserField function for table inline editing
    const onUpdateUserField = (userId, field, value, metaData = {}, successCallback, errorCallback) => {
        const isUserField = getIsUserField(field);
        if (isUserField) {
            if (field === USER_ENTITY_FIELDS.BIRTHDAY) {
                value = getDateFromTimestamp(value)
            }
        }
        fieldsStore.updateUserValue(
            userId, 
            field, 
            value,
            systemStore.constants.field_target_type.USER, 
            metaData, 
            () => {

                successCallback();
                useProfileStore.getState().fetch(userId, false, isPartnerSelected);
                const successMessage = getFieldUpdateSuccessMessage(field, useFieldsStore.getState().fieldIdToValueMapping);
                useNotificationSystemStore.getState().message(successMessage, NOTIFICATION_SEVERITIES.SUCCESS);
            }, 
            errorCallback
        );
    };

    // Initialize fieldsRegistry and fieldsOrder early to avoid reference errors
    const fieldsRegistry = useMemo(() => {
        const currentProfileData = isPartnerSelected ? profileStore.partnerProfile : profileStore.profile;
        return buildFieldRegistry({
            collect_first_name: organizationStore.userOrganizationDetails.collect_first_name,
            collect_last_name: organizationStore.userOrganizationDetails.collect_last_name,
            profileData: currentProfileData,
            isShowEmptyValues: true,
            isEdit: true,
            isEditSensitiveData: true,
            isShowFullProfile: true,
            measurement_unit: organizationStore.userOrganizationDetails.measurement_unit,
            is_use_objectives: organizationStore.userOrganizationDetails.is_use_objectives,
            isShowContact: true,
            userCustomFields: currentProfileData.custom_fields,
            fieldIdToValueMapping: fieldsStore.fieldIdToValueMapping,
            isPublicEdit: false,
            isShowBigEditIcon: false,
            is_lgbtq: organizationStore.userOrganizationDetails.is_lgbtq,
            is_use_age_range: organizationStore.userOrganizationDetails.is_use_age_range,
        })
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isPartnerSelected, profileStore.partnerProfile, profileStore.profile, fieldsStore.fieldIdToValueMapping])

    const fieldsOrderState = uiSettingsStore.uiSettings[MODULE.USER].profileCard.fieldsOrder;
    const fieldsOrder = useMemo(() => {
        const currentFieldsOrder = uiSettingsStore.uiSettings[MODULE.USER].profileCard.fieldsOrder || {};
        const storedCustomFieldChangeTime = uiSettingsStore.custom_field_change_time;
        const dbCustomFieldChangeTime = organizationStore.userOrganizationDetails.custom_field_change_time;

        if (fieldsStore.isInitialized) {
            // ── 1. Handle custom field additions / removals (timestamp-driven) ──────
            const customFieldChanges = handleCustomFieldChanges(
                currentFieldsOrder,
                storedCustomFieldChangeTime,
                dbCustomFieldChangeTime,
                fieldsStore.customFieldsData,
                uiSettingsStore.uiSettings[MODULE.USER].table || {}
            );

            if (customFieldChanges) {
                useUiSettingsStore.getState().updateFieldsOrder(customFieldChanges.fieldsOrder);
                if (customFieldChanges.tableSettings.columnsVisible) {
                    useUiSettingsStore.getState().setColumnsVisible(MODULE.USER, customFieldChanges.tableSettings.columnsVisible);
                }
                if (customFieldChanges.tableSettings.columnsOrder) {
                    useUiSettingsStore.getState().setColumnsOrder(MODULE.USER, customFieldChanges.tableSettings.columnsOrder);
                }
                useUiSettingsStore.getState().setCustomFieldChangeTime(customFieldChanges.newTimestamp);
                return customFieldChanges.fieldsOrder;
            }

            // ── 2. Initialize if empty ───────────────────────────────────────────────
            const initialization = initializeFieldsOrderIfEmpty(
                currentFieldsOrder,
                fieldsStore.customFieldsData,
                fieldsRegistry,
                dbCustomFieldChangeTime
            );

            if (initialization) {
                useUiSettingsStore.getState().updateFieldsOrder(initialization.fieldsOrder);
                if (initialization.newTimestamp) {
                    useUiSettingsStore.getState().setCustomFieldChangeTime(initialization.newTimestamp);
                }
                return initialization.fieldsOrder;
            }

            // ── 3. Clean up flag-gated fields and duplicates ─────────────────────────
            const cleaned = cleanupFieldsOrder(
                currentFieldsOrder,
                fieldsRegistry,
                organizationStore.userOrganizationDetails.is_lgbtq,
                organizationStore.userOrganizationDetails.is_use_objectives,
                organizationStore.userOrganizationDetails.collect_first_name,
                organizationStore.userOrganizationDetails.is_use_age_range
            );

            if (buildDataString(cleaned) !== buildDataString(currentFieldsOrder)) {
                useUiSettingsStore.getState().updateFieldsOrder(cleaned);
            }

            return cleaned;
        }

        return currentFieldsOrder;

        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        fieldsOrderState,
        fieldsStore.fieldIdToValueMapping,
        fieldsStore.isInitialized,
        fieldsRegistry,
        uiSettingsStore.custom_field_change_time,
        organizationStore.userOrganizationDetails.custom_field_change_time,
        organizationStore.userOrganizationDetails.is_lgbtq,
        organizationStore.userOrganizationDetails.is_use_objectives,
        organizationStore.userOrganizationDetails.collect_first_name,
    ]);

    const handleOpenHelp = () => {
        helpStore.setActiveHelp(MODULE.USER);
        setDrawerOpen(true);
    };

    const handleDrawerClose = () => {
        setDrawerOpen(false);
        helpStore.setActiveHelp();
    };

    useEffect(() => {
        const savedDefault = uiSettingsStore.uiSettings[MODULE.USER]?.searchFilter?.default;
        const initialFilters = (IS_OWNER && savedDefault) ? savedDefault : EMPTY_USER_FILTERS;
        usersState.onFiltersSelected(cloneFilters(initialFilters));
        if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.CUSTOM_FIELD)) {
            fieldsStore.init({ meta_data: { target: systemStore.constants.field_target.USER } });
        }
        organizationStore.getOrganizationAdminUsers();
        if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.PACKAGE)) {
            packageStore.all();
        }
        if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.FORM)) {
            formStore.getAll();
        }
        if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.WORKFLOW)) {
            workflowStore.all({is_built_in: true});
        }
        return () => {
            fieldsStore.reset();
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [systemStore.isInitialized]);

    const isHasBuiltInExternalizeWorkflow = useMemo(() => {
        return !!organizationStore.userOrganizationDetails.share_profile_workflow_email_id;
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [organizationStore.userOrganizationDetails.share_profile_workflow_email_id])

    useEffect(() => {
        if (selectedUserStore.selectedUsers.length === 1) {
            profileStore.fetch(selectedUserStore.selectedUsers[0].id);
        } else if (selectedUserStore.selectedUsers.length === 2) {
            profileStore.fetch(selectedUserStore.selectedUsers[0].id);
            profileStore.fetch(selectedUserStore.selectedUsers[1].id, true, true);
            if (
                selectedUserStore.selectedUsers[0].conversation_id &&
                selectedUserStore.selectedUsers[1].conversation_id &&
                selectedUserStore.selectedUsers[0].conversation_id ===
                selectedUserStore.selectedUsers[1].conversation_id
            ) {
                conversationStore.fetchStatistics(
                    selectedUserStore.selectedUsers[0].id,
                    selectedUserStore.selectedUsers[0].conversation_id
                );
            } else {
                conversationStore.fetchAgreement(
                    selectedUserStore.selectedUsers[0].id,
                    selectedUserStore.selectedUsers[1].id
                );
            }
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedUserStore.selectedUsers]);

    useEffect(() => {
        if (gridRef.current.api) {
            gridRef.current.api.deselectAll();
        }
    }, [usersState.filtersSelected]);

    const onColumnPinned = (params) => {
        gridRef.current.api.redrawRows();
        usersState.pinUser(params.data.id);
    };

    useEffect(() => {
        return () => {
            setIsPartnerSelected(false)
            setShowProfile(false)
            setShowConversationDiff(false)
            setShowConversationStats(false)
        };
    }, []);

    const isDisabledPin = (params) => {
        return params.data &&
            (params.data._isPinned === undefined || params.data._isPinned === false) &&
            useUsersStore.getState().pinnedUsers.length === 4
            ? true
            : false;
    }

    const isPinned = (params) => {
        const _pinnedUsers = useUsersStore.getState().pinnedUsers;
        return params.data && _pinnedUsers.some(user => user?.id === params.data.id);
    }

    const isDisabledCheckbox = (params) => {
        const _selectedUserStore = useSelectedUsersStore.getState();
        return params.data && _selectedUserStore.selectedUsers.length >= 2 && !_selectedUserStore.selectedUsers.some(user => user?.id === params.data.id);
    }

    const isCheckboxChecked = (params) => {
        const _selectedUserStore = useSelectedUsersStore.getState();
        return params.data && _selectedUserStore.selectedUsers.some(user => user?.id === params.data.id);
    }

    const getPackageTimeLeft = (params) => {
        const currentDate = moment();
        const startDate = moment(params.data.package_start_date);
        const endDate = moment(params.data.package_end_date);

        if (params.data.package_end_date && params.data.package_start_date) {
            if (currentDate.isAfter(endDate)) {
                return i18n.t('general.expired');
            }

            if (currentDate.isAfter(startDate)) {
                return getTimeDifferenceString(currentDate, endDate);
            } else {
                return i18n.t('general.notStarted');
            }

        }
    }

    const getFormName = (params) => {
        return formStore.formsToIdMapping[params.data.created_by_form_id]?.name || '';
    }

    useEffect(() => {
        const isMetric = organizationStore.userOrganizationDetails.measurement_unit === systemStore.constants.measurement_unit?.METRIC;
        let _columns = [
            Img((params) =>
                getFacialPhotoSource(params.data.facial_photo_external_id, USER_PHOTO_TRANSFORM),
                AVATAR_IMG_WIDTH_HEIGHT,
                undefined,
                COLUMN_SELECTION_CATEGORIES.USER,
            ),
            Age(),
            Height(isMetric, USER_ENTITY_FIELDS.HEIGHT, i18n.t('general.height')),
