    const { mappedSubCategoriesForManualCreate, unmappedFieldsForManualCreate, customFieldsForValidation } = useMemo(() => {
        const fieldMetadata = fieldsStore.fieldIdToValueMapping;
        const filteredMappedSubCategories = mappedSubCategories
            .map(category => {
                const orderedFields = (category.orderedFields || []).filter(entry => {
                    if (entry.kind === 'custom') {
                        return entry.field?.meta_data?.is_show_on_manual_user_create;
                    }
                    return is_show_on_manual_user_create(entry.name, fieldMetadata);
                });
                return {
                    ...category,
                    fields: category.fields.filter(field => field.meta_data?.is_show_on_manual_user_create),
                    builtinFieldNames: (category.builtinFieldNames || []).filter(name => is_show_on_manual_user_create(name, fieldMetadata)),
                    orderedFields,
                };
            })
            .filter(category => category.fields.length > 0 || category.builtinFieldNames.length > 0);

        const filteredUnmappedFields = unmappedFields.filter(field => field.meta_data?.is_show_on_manual_user_create);

        // Collect all custom fields that are part of the form for validation
        const fieldsForValidation = [];
        filteredMappedSubCategories.forEach(category => {
            fieldsForValidation.push(...category.fields);
        });
        fieldsForValidation.push(...filteredUnmappedFields);

        return {
            mappedSubCategoriesForManualCreate: filteredMappedSubCategories,
            unmappedFieldsForManualCreate: filteredUnmappedFields,
            customFieldsForValidation: fieldsForValidation
        };
