    const validateFormSelection = (dialogParams) => {
        if (!dialogParams || Object.keys(dialogParams).length === 0) {
            return false;
        }

        const isOptionalFieldValid = (field) => {
            return !field.value || field.valid;
        };

        // List of built-in field names to validate
        const builtInFieldNames = [
            USER_ENTITY_FIELDS.EMAIL, 
            USER_ENTITY_FIELDS.FIRST_NAME, 
            USER_ENTITY_FIELDS.MIDDLE_NAME, 
            USER_ENTITY_FIELDS.LAST_NAME, 
            USER_ENTITY_FIELDS.BIRTHDAY,
            USER_ENTITY_FIELDS.GENDER, 
            USER_ENTITY_FIELDS.GENDER_IDENTITY, 
            USER_ENTITY_FIELDS.HEIGHT, 
            USER_ENTITY_FIELDS.TYPE, 
            USER_ENTITY_FIELDS.ORIENTATION,
            USER_ENTITY_FIELDS.IS_SMOKING,
            USER_ENTITY_FIELDS.HAVE_KIDS, 
            USER_ENTITY_FIELDS.WAS_MARRIED, 
            USER_ENTITY_FIELDS.WANT_SMOKING,
            USER_ENTITY_FIELDS.AGE_YEARS_OLDER, 
            USER_ENTITY_FIELDS.AGE_YEARS_YOUNGER, 
            USER_ENTITY_FIELDS.HEIGHT_FROM_CM, 
            USER_ENTITY_FIELDS.HEIGHT_TO_CM
        ];

        // Validate built-in fields dynamically based on userFieldsData
        for (const fieldName of builtInFieldNames) {
            const fieldMetadata = fieldsStore.fieldIdToValueMapping[fieldName];

            // Only validate if field is configured to show on manual user create
            if (is_show_on_manual_user_create(fieldMetadata)) {
                const fieldValue = dialogParams[fieldName];
                const isRequired = fieldMetadata.meta_data?.required_on_manual_create;

                if (isRequired) {
                    if (!fieldValue || !fieldValue.valid) {
                        return false;
                    }
                } else {
                    if (!isOptionalFieldValid(fieldValue)) {
                        return false;
                    }
                }
            }
        }

        // Validate custom fields (only those that are part of the form)
        for (const customField of customFieldsForValidation) {
            const fieldValue = dialogParams[customField.id];
            const isRequired = customField.meta_data?.required_on_manual_create;

            if (isRequired) {
                // YES_NO fields can legitimately be `false`, so check emptiness
                // explicitly instead of using truthiness on the value.
                if (!fieldValue || isEmptyValue(fieldValue.value)) {
                    return false;
                }
            }
        }

        return true;
    };

