    const updateSelectRows = (newRow, isCheckboxSelection = false) => {
        const _selectedUserStore = useSelectedUsersStore.getState();
        if (newRow.data) {
            useLocalStorageStore.getState().addRecentlyViewedUserId(newRow.data.id);
            const { event } = newRow;
            const isCtrlOrCmdPressed = event?.ctrlKey || event?.metaKey;
            if (isCtrlOrCmdPressed || isCheckboxSelection) {
                if (_selectedUserStore.selectedUsers.length <= 2 && _selectedUserStore.selectedUsers.length > 0) {
                    const isSameRowSelected = _selectedUserStore.selectedUsers.some((row) => row.id === newRow.data.id);
                    if (!isSameRowSelected) {
                        if (_selectedUserStore.selectedUsers) {
                            _selectedUserStore.selectUsers([..._selectedUserStore.selectedUsers, newRow.data]);
                            setDrawerOpen(true);
                        }
                    } else {
                        const indexToRemove = _selectedUserStore.selectedUsers.findIndex((row) => row.id === newRow.data.id);
                        if (indexToRemove >= 0) {
                            const _selectedRows = [..._selectedUserStore.selectedUsers];
                            _selectedRows.splice(indexToRemove, 1);
                            _selectedUserStore.selectUsers(_selectedRows);
                        }
                    }
                } else {
                    _selectedUserStore.selectUsers([..._selectedUserStore.selectedUsers, newRow.data]);
