                    usersState.filtersSelected.delete_status?.length > 0 ||
                    Object.keys(usersState.filtersSelected).length > 1
                }
                searchQuery={searchQuery}
            />
        );
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        usersState.filterVisible,
        usersState.filtersSelected,
        usersState.filteredUsersCount,
        packageStore.packages,
        organizationStore.userOrganizationDetails.measurement_unit,
        filterQueryAdditionalActions,
    ]);

    useEffect(() => {
        const topRightActions = [];
        if(organizationStore.userOrganizationDetails.is_can_create_user) {
            topRightActions.push(
                {
                    icon: <CreateUserIcon className="page-action-icon" />,
                    tooltip: i18n.t('tooltip.user.createNewUser'),
                    onClick: () => { 
                        const additionalButtons = [
                            {
                                label: i18n.t('general.clear'),
                                onClick: () => {
                                    useLocalStorageStore.getState().clearCreateUserFormState();
                                },
                                variant: 'outlined',
                            },
                            {
                                label: i18n.t('general.previous'),
                                onClick: () => {
                                    createUserContentRef.current?.previousTab();
                                },
                                variant: 'outlined',
                            },
                            {
                                label: i18n.t('general.next'),
                                onClick: () => {
                                    // HTML5 form validation will handle validation
                                    if (createUserContentRef.current?.validateCurrentTab()) {
                                        createUserContentRef.current?.nextTab();
                                    }
                                },
                                variant: 'contained',
                            },
                        ];

                        showCreateNewUserDialog(
                            handleCreateUserSubmit,
                            validateFormSelection,
                            organizationStore.userOrganizationDetails.measurement_unit,
                            mappedSubCategoriesForManualCreate,
                            unmappedFieldsForManualCreate,
                            packageStore.packages,
                            createUserContentRef,
                            additionalButtons
                        ) 
                    }
                }
            )
        }
        setLayoutProps({
            title: i18n.t('general.users'),
            icon: MODULE_ICONS[MODULE.USER],
            isEnableFilterShortcut: !drawerOpen,
            topRightActions: topRightActions,
            filtersSearchQuery: filtersSearchQuery,
            topBarHelpHandler: handleOpenHelp,
            onToggleShowFilter: usersState.toggleShowFilter,
        });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        organizationStore.userOrganizationDetails.is_can_create_user,
        organizationStore.userOrganizationDetails.measurement_unit,
        usersState.filtersSelected,
        filtersSearchQuery,
        mappedSubCategoriesForManualCreate,
        unmappedFieldsForManualCreate,
        packageStore.packages,
        createUserContentRef,
    ])

    const drawerTopRightElements = [];

    if (IS_OWNER) {
        drawerTopRightElements.push(
            <EditModeButton 
                key='drawer_edit_mode' 
                isActive={isDrawerEditMode} 
                onClick={() => setIsDrawerEditMode(!isDrawerEditMode)}
            />
        )
    }

    const buildRowMenuItems = (params) => {
        return buildUserRowMenuItems(params, {
            onOpen: updateSelectRows,
            onDeleteUser: deleteUser,
            onSetInactive: setUserInactive,
            onPromoteToUser: promoteToUser,
            onGetFeedbackLink: getFeedbackLink,
            onResetAllOrgUsers: godStore.resetAllOrgUsers,
            onDownloadCustomUserPdf: usersState.downloadCustomUserPdf,
            onFindMatches: findMatches,
            navigate,
        });
    };

    return (
        <PageLayoutTableDrawerFilter
            // FILTERS PROPS
            visibleFilter={usersState.filterVisible}
            onToggleShowFilter={() => { usersState.toggleShowFilter(); setIsFilterEditMode(false); }}
            filterContent={filterContent}
            filterTopRightActions={filterTopRightActions}
            clearFocusFilterKey={() => usersState.clearFocusFilterKey()}
            focusFilterKey={usersState.focusFilterKey}

            // TABLE PROPS
            isLoading={props.isLoading}
            gridRef={gridRef}
            tableData={null}
            tableColumns={columns}
            getRowContextMenuItems={buildRowMenuItems}
            onCellClicked={(e) => {
                const editableCustomFieldsMap = useFieldsStore.getState().editableCustomFieldsMap || {};
                const isEditableCustomField = editableCustomFieldsMap[e.colDef.field];
                if (!['find_matches_row', 'pin_row', 'select_row', MENU_ACTION_COLUMN_NAME].includes(e.colDef.field) && !isEditableCustomField) {
                    updateSelectRows(e);
                }
            }}
            pinnedTopRowData={usersState.pinnedUsers}
            filtersSelected={usersState.filtersSelected}
            fetch={usersState.search}
            infiniteScrollPagination={true}
            moduleId={MODULE.USER}
            onSelectionChanged={onSelectionChanged}
            isPinnedRightCol={true}
            isPinnedLeftCol={true}
            isAutoFocus={!usersState.filterVisible}
            sortable={true}
            enableInlineEditing={true}
            onUpdateUserField={onUpdateUserField}

            // DRAWER PROPS
            drawerOpen={drawerOpen}
            setDrawerOpen={setDrawerOpen}
            resetDrawer={handleDrawerClose}
            sideDrawerClassName={`users-drawer ${isRTL() && 'rtl'}`}
            drawerContent={drawerContent}
            topRightElements={drawerTopRightElements}
        />
    );
};

export default Users;

Users.defaultProps = {
    isLoading: false,
};

