const [showConversationStats, setShowConversationStats] = useState(false);
const [isDrawerEditMode, setIsDrawerEditMode] = useState(false);
const [isFilterEditMode, setIsFilterEditMode] = useState(false);

const { setLayoutProps } = useLayout();

const LICENSE = getModuleLicense(systemStore.constants.module_type.USER);
const IS_OWNER = adminUserStore.userInfo?.is_owner;
const IS_EDIT_LICENSE = LICENSE <= systemStore.constants.license_type.UPDATE;

const onFilterTabsReorder = (newTabs) => {
    uiSettingsStore.setSearchFilterTabsOrder(MODULE.USER, newTabs.map(tab => tab.value));
};

const savedDefaultFilters = uiSettingsStore.uiSettings[MODULE.USER]?.searchFilter?.default ?? null;

const cloneFilters = (filters) => JSON.parse(JSON.stringify(filters || {}));

const filterTopRightActions = useMemo(() => {
    const actions = [
        <EditModeButton
            key='search_filter_edit_mode'
            isActive={isFilterEditMode}
            onClick={() => setIsFilterEditMode(!isFilterEditMode)}
        />,
        <DefaultFiltersButton
            key='default_filters_button'
            currentFilters={usersState.filtersSelected}
            defaultFilters={savedDefaultFilters}
            packages={packageStore.packages}
            measurement_unit={organizationStore.userOrganizationDetails.measurement_unit}
            entityType='users'
            onSetDefault={() => {
                const hasKeys = usersState.filtersSelected && Object.keys(usersState.filtersSelected).length > 0;
                const snapshot = hasKeys ? cloneFilters(usersState.filtersSelected) : cloneFilters(EMPTY_USER_FILTERS);
                uiSettingsStore.setDefaultSearchFilters(MODULE.USER, snapshot);
            }}
            onApplyDefault={() => {
                usersState.onFiltersSelected(cloneFilters(savedDefaultFilters || EMPTY_USER_FILTERS));
                resetGrid();
            }}
            onClearDefault={() => {
                uiSettingsStore.resetDefaultSearchFilters(MODULE.USER);
            }}
        />
    ];
    return actions;
    // eslint-disable-next-line react-hooks/exhaustive-deps
}, [
    isFilterEditMode,
    usersState.filtersSelected,
    savedDefaultFilters,
    packageStore.packages,
    organizationStore.userOrganizationDetails.measurement_unit,
]);
// Create onUpdateUserField function for table inline editing
const onUpdateUserField = (userId, field, value, metaData = {}, successCallback, errorCallback) => {
    const isUserField = getIsUserField(field);
    if (isUserField) {
        if (field === USER_ENTITY_FIELDS.BIRTHDAY) {
            value = getDateFromTimestamp(value)
        }
    }
    fieldsStore.updateUserValue(
        userId, 
        field, 
        value,
        systemStore.constants.field_target_type.USER, 
        metaData, 
        () => {

            successCallback();
            useProfileStore.getState().fetch(userId, false, isPartnerSelected);
            const successMessage = getFieldUpdateSuccessMessage(field, useFieldsStore.getState().fieldIdToValueMapping);
            useNotificationSystemStore.getState().message(successMessage, NOTIFICATION_SEVERITIES.SUCCESS);
        }, 
        errorCallback
    );
};

// Initialize fieldsRegistry and fieldsOrder early to avoid reference errors
const fieldsRegistry = useMemo(() => {
    const currentProfileData = isPartnerSelected ? profileStore.partnerProfile : profileStore.profile;
    return buildFieldRegistry({
        collect_first_name: organizationStore.userOrganizationDetails.collect_first_name,
        collect_last_name: organizationStore.userOrganizationDetails.collect_last_name,
        profileData: currentProfileData,
        isShowEmptyValues: true,
        isEdit: true,
        isEditSensitiveData: true,
        isShowFullProfile: true,
        measurement_unit: organizationStore.userOrganizationDetails.measurement_unit,
        is_use_objectives: organizationStore.userOrganizationDetails.is_use_objectives,
        isShowContact: true,
        userCustomFields: currentProfileData.custom_fields,
        fieldIdToValueMapping: fieldsStore.fieldIdToValueMapping,
        isPublicEdit: false,
        isShowBigEditIcon: false,
        is_lgbtq: organizationStore.userOrganizationDetails.is_lgbtq,
        is_use_age_range: organizationStore.userOrganizationDetails.is_use_age_range,
    })
    // eslint-disable-next-line react-hooks/exhaustive-deps
}, [isPartnerSelected, profileStore.partnerProfile, profileStore.profile, fieldsStore.fieldIdToValueMapping])

const fieldsOrderState = uiSettingsStore.uiSettings[MODULE.USER].profileCard.fieldsOrder;
const fieldsOrder = useMemo(() => {
    const currentFieldsOrder = uiSettingsStore.uiSettings[MODULE.USER].profileCard.fieldsOrder || {};
