    const dbCustomFieldChangeTime = organizationStore.userOrganizationDetails.custom_field_change_time;

    if (fieldsStore.isInitialized) {
        // ── 1. Handle custom field additions / removals (timestamp-driven) ──────
        const customFieldChanges = handleCustomFieldChanges(
            currentFieldsOrder,
            storedCustomFieldChangeTime,
            dbCustomFieldChangeTime,
            fieldsStore.customFieldsData,
            uiSettingsStore.uiSettings[MODULE.USER].table || {}
        );

        if (customFieldChanges) {
            useUiSettingsStore.getState().updateFieldsOrder(customFieldChanges.fieldsOrder);
            if (customFieldChanges.tableSettings.columnsVisible) {
                useUiSettingsStore.getState().setColumnsVisible(MODULE.USER, customFieldChanges.tableSettings.columnsVisible);
            }
            if (customFieldChanges.tableSettings.columnsOrder) {
                useUiSettingsStore.getState().setColumnsOrder(MODULE.USER, customFieldChanges.tableSettings.columnsOrder);
            }
            useUiSettingsStore.getState().setCustomFieldChangeTime(customFieldChanges.newTimestamp);
            return customFieldChanges.fieldsOrder;
        }

        // ── 2. Initialize if empty ───────────────────────────────────────────────
        const initialization = initializeFieldsOrderIfEmpty(
            currentFieldsOrder,
            fieldsStore.customFieldsData,
            fieldsRegistry,
            dbCustomFieldChangeTime
        );

        if (initialization) {
            useUiSettingsStore.getState().updateFieldsOrder(initialization.fieldsOrder);
            if (initialization.newTimestamp) {
                useUiSettingsStore.getState().setCustomFieldChangeTime(initialization.newTimestamp);
            }
            return initialization.fieldsOrder;
        }

