import React, { useEffect, useMemo, useRef, useState } from 'react';

import i18n from '../../i18n';
import Panel from '../../components/Panel/Panel';

import './Communication.scss';
import ConversationMessages from '../../components/Communication/ConversationMessages';
import ConversationInput from '../../components/Communication/ConversationInput';
import { useCommunicationStore } from '../../store/communication/communicationStore';
import { useUsersStore } from '../../store/users/usersStore';
import { showNewChatDialog } from '../../store/window/helpers';
import { useSystemStore } from '../../store/system/systemStore';
import { messagesQueue } from '../../store/communication/helpers';
import ContentAndSidePanel from '../../components/Layout/ContentAndSidePanel';
import ContentBySidePanelWrap from '../../components/Layout/ContentBySidePanelWrap';
import ConversationList from '../../components/Communication/ConversationList';
import { useFieldsStore } from '../../store/fields/fieldsStore';
import { usePackageStore } from '../../store/package/packageStore';
import { convertModulesToInt } from '../../store/system/helpers';
import { useAdminUserStore } from '../../store/adminUser/adminUserStore';
import { useSelectedUsersStore } from '../../store/users/selectedUsersStore';
import { getModuleLicense } from '../../helpers';
import { MODULE, MODULE_ICONS } from '../../constants';
import { useHelpStore } from "../../store/help/helpStore";
import Help from "../../components/Help/Help";
import SideDrawer from '../../components/SideDrawer/SideDrawer';
import { useLayout } from '../../components/PageLayout/LayoutContext/LayoutContext';
import AddIcon from '@mui/icons-material/Add';
import { getUserFullName } from '@ob-love/ui';

const Communication = (props) => {
    const messagesRef = useRef();
    const [newSelecteduserName , setNewSelectedUserName] = useState(undefined);

    const communicationStore = useCommunicationStore((state) => state);
    const userStore = useUsersStore((state) => state);
    const systemStore = useSystemStore((state) => state);
    const fieldsStore = useFieldsStore((state) => state);
    const packageStore = usePackageStore((state) => state);
    const adminUserStore = useAdminUserStore((state) => state);
    const selectedUserStore = useSelectedUsersStore((state) => state);
    const helpStore = useHelpStore((state) => state);
    const [drawerOpen, setDrawerOpen] = useState(false);

    const { setLayoutProps } = useLayout();

    const HAS_ADMIN_ACCESS = useMemo(() => {
        return (
            systemStore.constants.license_type.ADMIN >=
            getModuleLicense(systemStore.constants.module_type.COMMUNICATION)
        );
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        systemStore.constants,
        systemStore.modules,
    ]);

    const handleOpenHelp = () => {
        helpStore.setActiveHelp(MODULE.COMMUNICATION);
        setDrawerOpen(true);
    };
    const handleDrawerClose = () => {
        setDrawerOpen(false);
        helpStore.setActiveHelp();
    };
    const searchFilter = useMemo(() => {
        const filter = {
            status: [
            systemStore.constants.user_status.ACTIVE,
            systemStore.constants.user_status.WAIT_COMPLETE,
            systemStore.constants.user_status.WAIT_APPROVAL,
            ],
        };

        if (!HAS_ADMIN_ACCESS) {
            filter.admin_user_id = adminUserStore.userInfo.id;
        }

        return filter;
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [
        HAS_ADMIN_ACCESS,
        adminUserStore.userInfo.id,
    ]);


    useEffect(() => {
        userStore.reset();
        selectedUserStore.reset();
        return () => {
            fieldsStore.reset();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    useEffect(() => {
        if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.PACKAGE)) {
            packageStore.all();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [communicationStore.current_participant]);


    const initNewConversation = (conversationId, participants) => {
        communicationStore.initConversation(conversationId, participants);
    }  

    const startNewChat = (user) => {
        setNewSelectedUserName(getUserFullName(user));
        communicationStore.addNewConversation(user);
    }

    useEffect(() => {
        if(systemStore.isInitialized) {
            if(adminUserStore.userInfo.id) {
                communicationStore.reset();
                setTimeout(() => loadConversations(), 200);
            }
            if (convertModulesToInt(systemStore.modules).includes(systemStore.constants.module_type.CUSTOM_FIELD)) {
                fieldsStore.init({meta_data: {target: systemStore.constants.field_target.USER}});
            }
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [adminUserStore.userInfo, systemStore.isInitialized])

    useEffect(() => {
        communicationStore.readMessage();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [communicationStore.messages.length, communicationStore.conversation_id])

    const loadConversations = () => {
        if(!communicationStore.fetchingConversations && communicationStore.hasMoreConversations) {
            const filter = {};
            if(!HAS_ADMIN_ACCESS) {
                filter['admin_user_id'] = adminUserStore.userInfo.id;
            }
            communicationStore.loadConversations(filter);
        }
    }

    const onTyping = function(typing) {
        communicationStore.updateUserTyping(typing);
    }

    const scrollToBottom = () => {
        if (messagesRef && messagesRef.current) {
            setTimeout(() => {
                messagesRef.current.scrollToBottom({animated: true});
            }, 1000)
        }
    }

	const onSendMessage = function(message) {
        if (message && message.trim().length > 0) {
            messagesQueue.addCallback(() => communicationStore.sendNewMessage(message), 200);
            scrollToBottom();
        }
    }

    const onLoadPreviousMessages = function() {
        if(communicationStore.fetching === false && communicationStore.has_more_before && communicationStore.messages.length > 0) {
            communicationStore.addConversationMessagesBefore();
        }
	}

    const onNewChatUserSearch = (value) => {
        const _searchFilter = JSON.parse(JSON.stringify(searchFilter));
        if(value.length > 0) {
            _searchFilter.name_email = value;
        }
        userStore.onFiltersSelected(_searchFilter, true);
    }

    const onShowNewChatDialog = () => {
        userStore.onFiltersSelected(searchFilter, true);
        onNewChatUserSearch('');
        showNewChatDialog(onNewChatUserSearch, startNewChat, (user) => selectedUserStore.selectUsers([user]))
    }

    const topRightActions = [
        {
            icon: <AddIcon className="page-action-icon" />,
            tooltip: i18n.t('communication.startNewChat'),
            onClick: onShowNewChatDialog
        }
    ]

    useEffect(() => {
        setLayoutProps({
            className: 'communication',
            title: i18n.t('general.communication'),
            icon: MODULE_ICONS[MODULE.COMMUNICATION],
            topBarHelpHandler: handleOpenHelp,
            topRightActions: topRightActions,
        });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);


    const conversationInput = communicationStore.conversation_id && (<ConversationInput onSendMessage={onSendMessage} onTyping={onTyping} />)
    return (
        <>
            <ContentAndSidePanel>
                <ContentBySidePanelWrap>
                    <Panel className='main-panel'>                    
                        <ConversationList
                            onClick={initNewConversation}
                            allConversations={communicationStore.allConversations}
                            conversationId={communicationStore.conversation_id}
                            isLoading={communicationStore.fetchingConversations}
                            loadConversations={loadConversations}
                        />
                        <div className='c-messages'>
                            <ConversationMessages 
                                ref={messagesRef} 
                                key={`conversation_${communicationStore.conversation_id}_${communicationStore.current_participant}`}
                                current_participant={communicationStore.current_participant}
                                selectedUserName={newSelecteduserName}
                                messages={communicationStore.messages}
                                has_more_before={communicationStore.has_more_before}
                                onLoadPrevious={onLoadPreviousMessages}
                                lastParticipantReadMessage={communicationStore.lastParticipantReadMessage}
                            />
                            {conversationInput}
                        </div>                
                    </Panel>
                </ContentBySidePanelWrap>
            </ContentAndSidePanel>
            <SideDrawer
                open={drawerOpen}
                onClose={handleDrawerClose}
                rightAction={null}
            >
                {<Help content={helpStore.currentHelp} />}
            </SideDrawer>
        </>
    );
}

export default Communication;

Communication.defaultProps = {

};

